// ── Group Classifier ──
export const implantGetGroup = c => {
  if (c.includes("Implant System")) return "Implant Systems";
  if (c.includes("Abutment")) return "Abutment Systems";
  if (c.includes("Attachment") || c.includes("Overdenture")) return "Overdenture Attachments";
  if (c.includes("Protocol") || c.includes("Decision Framework") || c.includes("Workflow")) return "Protocols & Decision Frameworks";
  return "Other";
};

